/*
 * ## MNIST handwritten digit classification example
 *
 * This example demonstrates how to use `feedforward_individual()`
 * from MLPico to run inference on pretrained MNIST digits using
 * incremental per-input feeding.
 *
 * Instead of feeding the entire input vector at once,
 * this API allows feeding one input value at a time.
 *
 * This is especially useful for:
 * - microcontrollers with very limited RAM
 * - streaming sensor/image pipelines
 * - realtime embedded inference
 *
 * After the final input is provided, the function returns
 * a pointer to the output layer activations.
 */

 
#define NumberOf(arg) ((unsigned int) (sizeof (arg) / sizeof (arg [0])))
#define MLPICO_OPTIMIZE 0B00010100 /* ENABLES int8_t quantization + MULTIPLE_BIASES_PER_LAYER */
#define Q_FLOAT_RANGE 5.0 /* is a float-range of -2.5 +2.5 mapped between -128 and +127 int8_t */
#define ACTIVATION__PER_LAYER /* allows the use of multiple activation functions to be defined */
        #define SIGMOID
        #define ELU
#define MLPICO_IMPLEMENTATION
#include "./../mlpico.h"
#include <stdio.h>


/* activation_function for each layer-to-layer */
const uint8_t activation_functions[] = {
  idx_elu,     /* Idx 1 = ELU     | Layers : 0 -> 1 */
  idx_elu,     /* Idx 1 = ELU     | Layers : 1 -> 2 */
  idx_sigmoid, /* Idx 0 = Sigmoid | Layers : 2 -> 3 */
};


/* Neuron counts per layer: input=784, hidden=12, hidden=9, output=10 */
const unsigned int layers[] = {784, 12, 9, 10};
/* Buffer size = (largest odd-indexed layer) + (largest even-indexed layer excluding the 0th one) =  12 + 9 thanks to feedforward_individual */
float buffer[21];
/* Just a semantic alias for buffer */
