unsigned int maxOutput()
{
  unsigned int maxi=0, i=0;
  for (; i < 10; i++)
    if (output[i] > output[maxi])
      maxi = i;
  return maxi;
}


int main(int argc, char *argv[])
{
  unsigned int i=NumberOf(handwritten_digits), j = 0;
  const MLPico mlp = {buffer, activation_functions, biases, weights, layers, 12, NumberOf(layers)}; /* 12 = (largest even-indexed layer excluding the 0th one) */

  /* goes (in reverse) through each handwritten-digit ... */
  while(i--){ 
    /* then goes through each individual-pixel ... */
    for (j = 0; j < 784; j++) 
      /* normalizes it between 0 and 1 before feeding it to the mlp, & at the end it returns the predicted output(s). */
      output = feedforward_individual(&mlp, handwritten_digits[i][j]/255.0, j); 
    /* prints the the index of the output-neuron that fired the highest */
    printf("Predicted: %d\n", maxOutput()); 
    /* Expected predictions: 4 0 7 3 */
  }

  return 0;
}
